import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // Wire hooks
  const submit = useAction<ActionSubmitPayload>('submit');

  // State management
  const [currentStep, setCurrentStep] = useState<number>(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: '',
  });

  // Validation state
  const [errors, setErrors] = useState({
    name: '',
    email: '',
  });

  // Email validation helper
  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  // Validate current step
  const validateStep = (step: number): boolean => {
    if (step === 1) {
      const newErrors = { name: '', email: '' };
      let isValid = true;

      if (!formData.name.trim()) {
        newErrors.name = 'Name is required';
        isValid = false;
      }

      if (!formData.email.trim()) {
        newErrors.email = 'Email is required';
        isValid = false;
      } else if (!validateEmail(formData.email)) {
        newErrors.email = 'Please enter a valid email address';
        isValid = false;
      }

      setErrors(newErrors);
      return isValid;
    }
    return true;
  };

  // Handle step navigation
  const handleNext = (): void => {
    if (validateStep(currentStep)) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = (): void => {
    setCurrentStep(currentStep - 1);
    setErrors({ name: '', email: '' });
  };

  // Handle form field changes
  const handleNameChange = (value: string): void => {
    setFormData({ ...formData, name: value });
    if (errors.name) setErrors({ ...errors, name: '' });
  };

  const handleEmailChange = (value: string): void => {
    setFormData({ ...formData, email: value });
    if (errors.email) setErrors({ ...errors, email: '' });
  };

  const handleSatisfactionChange = (value: string): void => {
    setFormData({ ...formData, satisfaction: parseInt(value, 10) });
  };

  const handleFeatureToggle = (feature: string): void => {
    setFormData(prev => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter(f => f !== feature)
        : [...prev.features, feature]
    }));
  };

  const handleCommentsChange = (value: string): void => {
    if (value.length <= 500) {
      setFormData({ ...formData, comments: value });
    }
  };

  // Handle final submission
  const handleSubmit = (): void => {
    submit({
      name: formData.name,
      email: formData.email,
      satisfaction: formData.satisfaction,
      features: formData.features,
      comments: formData.comments,
    });
  };

  // Determine if Next button should be disabled
  const isNextDisabled = (): boolean => {
    if (currentStep === 1) {
      return !formData.name.trim() || !formData.email.trim() || !validateEmail(formData.email);
    }
    if (currentStep === 2) {
      return formData.satisfaction === 0;
    }
    return false;
  };

  // Render satisfaction radio options
  const satisfactionOptions = props.satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label: label,
  }));

  // Render feature checkbox options
  const featureCheckboxes = props.featureOptions.map(feature => ({
    label: feature,
    checked: formData.features.includes(feature),
  }));

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)" align="center">
        {/* Progress bar */}
        <Box width="100%">
          <Stack gap="var(--ggui-spacing-2)">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              Step {currentStep} of 4
            </Text>
            <Progress
              value={currentStep}
              max={4}
              variant="default"
              size="md"
              aria-label={`Survey progress: Step ${currentStep} of 4`}
            />
          </Stack>
        </Box>

        {/* Step 1: Name and Email */}
        {currentStep === 1 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg" style={{ width: '100%', maxWidth: '600px' }}>
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Contact Information</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Please enter your name and email address.
              </Text>
              <Stack gap="var(--ggui-spacing-3)">
                <Input
                  label="Name"
                  placeholder="John Doe"
                  value={formData.name}
                  onChange={handleNameChange}
                  required
                  error={errors.name}
                />
                <Input
                  label="Email"
                  type="email"
                  placeholder="john@example.com"
                  value={formData.email}
                  onChange={handleEmailChange}
                  required
                  error={errors.email}
                />
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg" style={{ width: '100%', maxWidth: '600px' }}>
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Satisfaction Rating</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                How satisfied are you with our service?
              </Text>
              <RadioGroup
                label="How satisfied are you with our service?"
                value={String(formData.satisfaction)}
                onChange={handleSatisfactionChange}
                options={satisfactionOptions}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg" style={{ width: '100%', maxWidth: '600px' }}>
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Feature Interests</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Which features interest you? (Select all that apply)
              </Text>
              <Stack gap="var(--ggui-spacing-2)">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={formData.features.includes(feature)}
                    onChange={() => handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg" style={{ width: '100%', maxWidth: '600px' }}>
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Additional Comments</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Please share any additional feedback or comments (optional).
              </Text>
              <TextArea
                label="Comments"
                placeholder="Share your thoughts here..."
                value={formData.comments}
                onChange={handleCommentsChange}
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Review */}
        {currentStep === 5 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg" style={{ width: '100%', maxWidth: '600px' }}>
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Review Your Answers</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Please review your responses before submitting.
              </Text>
              <Stack gap="var(--ggui-spacing-3)" style={{ backgroundColor: 'var(--ggui-color-surfaceVariant)', padding: 'var(--ggui-spacing-4)', borderRadius: 'var(--ggui-shape-radius-md)' }}>
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                  <Text variant="body">{formData.name}</Text>
                </Box>
                <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                  <Text variant="body">{formData.email}</Text>
                </Box>
                <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction</Text>
                   <Text variant="body">{formData.satisfaction > 0 ? props.satisfactionLabels[formData.satisfaction - 1] : 'Not rated'}</Text>
                </Box>
                <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Features of Interest</Text>
                  <Text variant="body">{formData.features.length > 0 ? formData.features.join(', ') : 'None selected'}</Text>
                </Box>
                <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Comments</Text>
                  <Text variant="body">{formData.comments || 'No comments provided'}</Text>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="center" style={{ width: '100%', maxWidth: '600px', marginTop: 'var(--ggui-spacing-4)' }}>
          {currentStep > 1 && (
            <Button
              variant="outline"
              onClick={handleBack}
              size="md"
            >
              Back
            </Button>
          )}

          {currentStep < 5 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={isNextDisabled()}
              size="md"
            >
              Next
            </Button>
          )}

          {currentStep === 5 && (
            <Button
              variant="primary"
              onClick={handleSubmit}
              size="md"
            >
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

