import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Helper sub-component: Task Card
// Helper sub-component: Task Card
function TaskCard({
  task,
  onMove,
  onEdit,
  availableColumns,
}: {
  task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; dueDate?: string };
  onMove: (columnId: string) => void;
  onEdit: (newTitle: string) => void;
  availableColumns: Array<{ id?: string; name?: string }>;
}) {
  const [isEditing, setIsEditing] = useState(false);
  const [editValue, setEditValue] = useState(task.title || '');
  const [showMoveMenu, setShowMoveMenu] = useState(false);

  const priorityVariant = (priority?: string): 'default' | 'primary' | 'success' | 'warning' | 'error' => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
        return 'success';
      default:
        return 'default';
    }
  };

  const handleEditSave = () => {
    if (editValue.trim()) {
      onEdit(editValue);
      setIsEditing(false);
    }
  };

  return (
    <Card shadow="sm" padding="var(--ggui-spacing-4)" radius="md" border={true}>
      <Stack gap="var(--ggui-spacing-2)">
        {isEditing ? (
          <Row gap="var(--ggui-spacing-2)" align="center">
            <Input
              label="Task title"
              value={editValue}
              onChange={setEditValue}
              placeholder="Task title"
            />
            <Button size="sm" variant="primary" onClick={handleEditSave}>
              Save
            </Button>
            <Button size="sm" variant="ghost" onClick={() => setIsEditing(false)}>
              Cancel
            </Button>
          </Row>
        ) : (
          <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
            <Text
              variant="body"
              as={Clickable}
              onClick={() => setIsEditing(true)}
              style={{ cursor: 'pointer', flex: 1 }}
            >
              {task.title || 'Untitled'}
            </Text>
            <Button size="xs" variant="ghost" onClick={() => setIsEditing(true)} leftIcon={<Icon name="edit" size={14} />}>
              Edit
            </Button>
          </Row>
        )}
        {task.priority && (
          <Badge variant={priorityVariant(task.priority)} size="sm">
            {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
          </Badge>
        )}
        <Row gap="var(--ggui-spacing-2)" align="center">
          {task.assignee && (
            <Avatar name={task.assignee} size="sm" shape="circle" />
          )}
          {task.dueDate && (
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              {new Date(task.dueDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}
            </Text>
          )}
        </Row>
        <Button
          size="sm"
          variant="outline"
          onClick={() => setShowMoveMenu(!showMoveMenu)}
          fullWidth
        >
          Move
        </Button>
        {showMoveMenu && (
           <Box paddingX="var(--ggui-spacing-2)" paddingY="var(--ggui-spacing-2)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-sm)">
            {availableColumns.map((col) => (
              <Button
                key={col.id}
                size="xs"
                variant="ghost"
                fullWidth
                onClick={() => {
                  onMove(col.id || '');
                  setShowMoveMenu(false);
                }}
              >
                {col.name}
              </Button>
            ))}
           </Box>
        )}
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Local state
  const [tasks, setTasks] = useState(props.tasks || []);
  const [newTaskForm, setNewTaskForm] = useState<{ [key: string]: { title: string; priority: 'low' | 'medium' | 'high' } }>({});

  // Sync tasks with stream updates
  useEffect(() => {
    if (taskChanged.latest?.action === 'create' || taskChanged.latest?.action === 'move' || taskChanged.latest?.action === 'edit') {
      if (taskChanged.latest.task?.id) {
        setTasks((prevTasks) => {
          const exists = prevTasks.find((t) => t.id === taskChanged.latest.task?.id);
          if (exists) {
            return prevTasks.map((t) => (t.id === taskChanged.latest.task?.id ? { ...t, ...taskChanged.latest.task } : t));
          } else {
            return [...prevTasks, taskChanged.latest.task];
          }
        });
      }
    } else if (taskChanged.latest?.action === 'delete' && taskChanged.latest.task?.id) {
      setTasks((prevTasks) => prevTasks.filter((t) => t.id !== taskChanged.latest.task?.id));
    }
  }, [taskChanged.latest]);

  // Group tasks by column
  const tasksByColumn = useMemo(() => {
    const grouped: { [key: string]: typeof tasks } = {};
    props.columns?.forEach((col) => {
      grouped[col.id || ''] = [];
    });
    tasks.forEach((task) => {
      const colId = task.column || '';
      if (grouped[colId]) {
        grouped[colId].push(task);
      }
    });
    return grouped;
  }, [tasks, props.columns]);

  // Calculate summary stats
  const totalTasks = tasks.length;
  const completedTasks = tasksByColumn['done']?.length || 0;

  // Handle task move
  const handleTaskMove = (taskId: string, targetColumn: string) => {
    setTasks((prevTasks) =>
      prevTasks.map((t) => (t.id === taskId ? { ...t, column: targetColumn } : t))
    );
    taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
  };

  // Handle task edit (title)
  const handleTaskEdit = (taskId: string, newTitle: string) => {
    setTasks((prevTasks) =>
      prevTasks.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t))
    );
    taskUpdate({ action: 'edit', taskId, data: { column: tasks.find((t) => t.id === taskId)?.column || 'todo' } });
  };

  // Handle add new task
  // Handle add new task — always starts in 'To Do' column
  const handleAddTask = (columnId: string) => {
    const form = newTaskForm[columnId];
    if (form?.title.trim()) {
      const newTask = {
        id: `task-${Date.now()}`,
        title: form.title,
        priority: form.priority,
        column: 'todo', // Always start in To Do column
      };
      setTasks((prev) => [...prev, newTask]);
      taskUpdate({ action: 'create', taskId: newTask.id, data: { column: 'todo' } });
      setNewTaskForm((prev) => ({ ...prev, [columnId]: { title: '', priority: 'low' } }));
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-lg)">
          <Row gap="var(--ggui-spacing-4)" justify="between" align="center">
            <Stack gap="var(--ggui-spacing-2)" direction="horizontal">
              <Text variant="label" color="var(--ggui-color-primary-700)">
                Total Tasks:
              </Text>
              <Text variant="label" weight="bold" color="var(--ggui-color-primary-900)">
                {totalTasks}
              </Text>
            </Stack>
            <Divider orientation="vertical" margin="var(--ggui-spacing-2)" />
            <Stack gap="var(--ggui-spacing-2)" direction="horizontal">
              <Text variant="label" color="var(--ggui-color-primary-700)">
                Completed:
              </Text>
              <Text variant="label" weight="bold" color="var(--ggui-color-success-700)">
                {completedTasks}
              </Text>
            </Stack>
          </Row>
        </Box>

        {/* Kanban Board */}
        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {props.columns?.map((column) => {
            const colId = column.id || '';
            const columnTasks = tasksByColumn[colId] || [];
            const form = newTaskForm[colId] || { title: '', priority: 'low' };

            return (
              <Box key={colId} style={{ flex: '1 1 300px', minWidth: '300px' }}>
                  <Card shadow="md" padding="var(--ggui-spacing-4)" radius="lg" border={true}>
                  <Stack gap="var(--ggui-spacing-4)">
                    {/* Column Header */}
                    <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
                      <Heading level={3} color="var(--ggui-color-onSurface)">
                        {column.name}
                      </Heading>
                      <Badge variant="secondary" size="sm">
                        {columnTasks.length}
                      </Badge>
                    </Row>
                    <Divider orientation="horizontal" margin="var(--ggui-spacing-3)" />

                    {/* Task List */}
                    <Stack gap="var(--ggui-spacing-3)">
                      {columnTasks.length === 0 ? (
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" align="center">
                          No tasks
                        </Text>
                      ) : (
                        columnTasks.map((task) => (
                          <Stack key={task.id} gap="var(--ggui-spacing-2)">
                            <TaskCard
                              task={task}
                              onMove={(targetCol) => handleTaskMove(task.id || '', targetCol)}
                              onEdit={(newTitle) => handleTaskEdit(task.id || '', newTitle)}
                              availableColumns={props.columns || []}
                            />
                            {/* Quick Move Buttons */}
                            <Row gap="var(--ggui-spacing-1)" justify="center">
                              {props.columns?.map((col) => {
                                if (col.id === colId) return null;
                                return (
                                  <Button
                                    key={col.id}
                                    size="xs"
                                    variant="ghost"
                                    onClick={() => handleTaskMove(task.id || '', col.id || '')}
                                  >
                                    → {col.name}
                                  </Button>
                                );
                              })}            
                            </Row>
                          </Stack>
                        ))
                      )}
                    </Stack>
                    <Divider orientation="horizontal" margin="var(--ggui-spacing-3)" />

                    {/* Add Task Form */}
                    <Stack gap="var(--ggui-spacing-3)">
                      <Input
                        label="New task title"
                        placeholder="Enter task title"
                        value={form.title}
                        onChange={(value) =>
                          setNewTaskForm((prev) => ({
                            ...prev,
                            [colId]: { ...form, title: value },
                          }))
                        }
                      />
                      <Select
                        label="Priority"
                        value={form.priority}
                        onChange={(value) =>
                          setNewTaskForm((prev) => ({
                            ...prev,
                            [colId]: { ...form, priority: value as 'low' | 'medium' | 'high' },
                          }))
                        }
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                      />
                      <Button
                        variant="primary"
                        fullWidth
                        onClick={() => handleAddTask(colId)}        
                      >
                        Add Task
                      </Button>
                    </Stack>
                  </Stack>
                </Card>
              </Box>
            );
          })}        
        </Row>
      </Stack>
    </Container>
  );
}

