};

const getColorForCategory = (category?: string) => {
  if (!category) return CATEGORY_COLORS['nonmetal'];
  const normalized = category.toLowerCase();
  return CATEGORY_COLORS[normalized] || CATEGORY_COLORS['nonmetal'];
};

