  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State
  const [allMessages, setAllMessages] = useState(props.messages || []);
  const [inputText, setInputText] = useState('');
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, []);

  // Update messages when new messages arrive via stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages(prev => [...prev, message.latest!]);
      scrollToBottom();
    }
  }, [message.latest, scrollToBottom]);

  // Handle typing indicator stream
  useEffect(() => {
    if (typing.latest) {
      setTypingUsers(prev => {
        const updated = new Set(prev);
        if (typing.latest?.active && typing.latest?.sender) {
          updated.add(typing.latest.sender);
        } else if (!typing.latest?.active && typing.latest?.sender) {
          updated.delete(typing.latest.sender);
        }
        return updated;
      });
      scrollToBottom();
    }
  }, [typing.latest, scrollToBottom]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputText.trim()) {
      sendMessage({
        text: inputText,
        timestamp: new Date().toISOString(),
      });
      setInputText('');
      scrollToBottom();
    }
  }, [inputText, sendMessage, scrollToBottom]);

  // Handle Enter key
  const handleKeyPress = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  // Format timestamp
  const formatTime = (isoString?: string) => {
    if (!isoString) return '';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  // Group consecutive messages by sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; messages: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    allMessages.forEach((msg) => {
      if (groups.length === 0 || groups[groups.length - 1].sender !== msg.sender) {
        groups.push({ sender: msg.sender, messages: [msg] });
      } else {
        groups[groups.length - 1].messages.push(msg);
      }
    });
    return groups;
  }, [allMessages]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" radius="lg" padding="var(--ggui-spacing-4)" border>
        <Stack gap="var(--ggui-spacing-4)" direction="vertical" align="stretch">
          {/* Header */}
          <Row gap="var(--ggui-spacing-4)" align="center" justify="between">
            <Stack gap="var(--ggui-spacing-2)" direction="vertical" align="start">
              <Heading level={2}>{props.title}</Heading>
            </Stack>
            <Badge variant="primary" size="md">
              {props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}
            </Badge>
          </Row>

          <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

          {/* Messages Container */}
          <Stack
            gap="var(--ggui-spacing-3)"
            direction="vertical"
            align="stretch"
            style={{
              maxHeight: '500px',
              overflowY: 'auto',
              paddingRight: 'var(--ggui-spacing-2)',
              paddingLeft: 'var(--ggui-spacing-2)',
            }}
          >
            {groupedMessages.map((group, groupIdx) => (
              <Stack
                key={`${group.sender}-${groupIdx}`}
                gap="var(--ggui-spacing-1)"
                direction="vertical"
                align={group.sender === props.currentUser ? 'end' : 'start'}
              >
                {group.sender && group.sender !== props.currentUser && (
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" size="xs">
                    {group.sender}
                  </Text>
                )}
                {group.messages.map((msg, msgIdx) => (
                  <Box
                    key={`${group.sender}-${groupIdx}-${msgIdx}`}
                    padding="var(--ggui-spacing-3)"
                    background={
                      group.sender === props.currentUser
                        ? 'var(--ggui-color-primary-600)'
                        : 'var(--ggui-color-surfaceVariant)'
                    }
                    borderRadius="var(--ggui-shape-radius-lg)"
                    style={{
                      maxWidth: '70%',
                      wordWrap: 'break-word',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-1)" direction="vertical" align="stretch">
                      <Text
                        color={
                          group.sender === props.currentUser
                            ? 'white'
                            : 'var(--ggui-color-onSurface)'
                        }
                        variant="body"
                      >
                        {msg.text}
                      </Text>
                      {msg.timestamp && (
                        <Text
                          variant="caption"
                          color={
                            group.sender === props.currentUser
                              ? 'rgba(255, 255, 255, 0.7)'
                              : 'var(--ggui-color-onSurfaceVariant)'
                          }
                          size="xs"
                        >
                          {formatTime(msg.timestamp)}
                        </Text>
                      )}
                    </Stack>
                  </Box>
                ))}
              </Stack>
            ))}

            {/* Typing Indicator */}
            {typingUsers.size > 0 && (
              <Stack gap="var(--ggui-spacing-2)" direction="vertical" align="start">
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant)"
                  size="xs"
                  style={{ fontStyle: 'italic' }}
                >
                  {Array.from(typingUsers).join(', ')} {typingUsers.size === 1 ? 'is' : 'are'} typing...
                </Text>
              </Stack>
            )}

            {/* Scroll anchor */}
            <div ref={messagesEndRef} />
          </Stack>

          <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

          {/* Input Area */}
          <Row gap="var(--ggui-spacing-2)" align="end" justify="between">
            <TextArea
              label="Message"
              value={inputText}
              onChange={setInputText}
              placeholder="Type your message here..."
              rows={3}
              onKeyDown={handleKeyPress}
              style={{ flex: 1 }}
            />
            <Button
              variant="primary"
              size="md"
              onClick={handleSendMessage}
              disabled={!inputText.trim()}
            >
              Send
            </Button>
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

