  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State management for displayed stocks and last update time
  const [displayedStocks, setDisplayedStocks] = useState(props.stocks);
  const [lastUpdatedTime, setLastUpdatedTime] = useState<Date>(new Date());
  const [updatingSymbols, setUpdatingSymbols] = useState<Set<string>>(new Set());
  const updateTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // Merge stream updates into displayed stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      const symbol = update.symbol;

      if (symbol) {
        setDisplayedStocks((prev) =>
          prev.map((stock) =>
            stock.symbol === symbol
              ? {
                  ...stock,
                  price: update.price ?? stock.price,
                  change: update.change ?? stock.change,
                  changePercent: update.changePercent ?? stock.changePercent,
                }
              : stock
          )
        );

        // Mark this symbol as updating for flash animation
        setUpdatingSymbols((prev) => new Set(prev).add(symbol));

        // Clear the update marker after animation completes
        if (updateTimeoutRef.current) {
          clearTimeout(updateTimeoutRef.current);
        }
        updateTimeoutRef.current = setTimeout(() => {
          setUpdatingSymbols((prev) => {
            const next = new Set(prev);
            next.delete(symbol);
            return next;
          });
        }, 600);

        setLastUpdatedTime(new Date());
      }
    }
  }, [priceUpdate.latest]);

  // Format last updated timestamp
  const formattedTime = useMemo(
    () => lastUpdatedTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' }),
    [lastUpdatedTime]
  );

  // Get market status from stream
  const currentMarketStatus = useMemo(
    () => marketStatus.latest?.status ?? 'closed',
    [marketStatus.latest]
  );

  const marketStatusColor =
    currentMarketStatus === 'open'
      ? 'var(--ggui-color-success-600)'
      : 'var(--ggui-color-warning-600)';

  return (
