            </Heading>
            <Row align="center" gap="var(--ggui-spacing-2)">
              <Badge
                variant={currentMarketStatus === 'open' ? 'success' : 'warning'}
                size="sm"
              >
                {currentMarketStatus.charAt(0).toUpperCase() + currentMarketStatus.slice(1).replace('-', ' ')}
              </Badge>
            </Row>
          </Row>
          <Text
            variant="bodySmall"
            color="var(--ggui-color-onSurfaceVariant)"
          >
            Last Updated: {formattedTime}
          </Text>
        </Stack>

        <Divider />

        {displayedStocks.length > 0 ? (
          <Box
            as="section"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
