  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<string>('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [touchedName, setTouchedName] = useState<boolean>(false);
  const [touchedEmail, setTouchedEmail] = useState<boolean>(false);
  const [submitted, setSubmitted] = useState<boolean>(false);

  const totalSteps = 5;
  const maxComments = 500;

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameValid = useMemo(() => name.trim().length > 0, [name]);
  const step1Valid = nameValid && emailValid;
  const step2Valid = satisfaction !== '';
  const commentsLength = comments.length;

  const canNext = useMemo(() => {
    if (step === 1) return step1Valid;
    if (step === 2) return step2Valid;
    if (step === 3) return true;
    if (step === 4) return true;
    return false;
  }, [step, step1Valid, step2Valid]);

  const progressValue = useMemo(() => (step / totalSteps) * 100, [step]);

  const handleToggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const handleNext = useCallback(() => {
    if (step === 1) {
      setTouchedName(true);
      setTouchedEmail(true);
      if (!step1Valid) return;
    }
    if (step === 2 && !step2Valid) return;
    setStep((prev) => (prev < totalSteps ? prev + 1 : prev));
  }, [step, step1Valid, step2Valid]);

  const handleBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleSubmit = useCallback(() => {
    const payload: ActionSubmitPayload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction),
      features,
      comments: comments.trim(),
    };
    submit(payload);
    setSubmitted(true);
  }, [name, email, satisfaction, features, comments, submit]);

  const nameError = touchedName && !nameValid ? 'Name is required.' : '';
  const emailError = touchedEmail
    ? email.trim().length === 0
      ? 'Email is required.'
      : !emailValid
        ? 'Please enter a valid email address.'
        : ''
    : '';

  const satisfactionOptions = useMemo(
    () =>
      (props.satisfactionLabels || []).map((label, index) => ({
        value: String(index + 1),
        label,
      })),
    [props.satisfactionLabels],
  );

  return (
