                <Input
                  label="Name"
                  value={name}
                  onChange={(value) => {
                    setName(value);
                    setTouchedName(true);
                  }}
                  required
                  placeholder="Enter your full name"
                  error={nameError || undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={(value) => {
                    setEmail(value);
                    setTouchedEmail(true);
                  }}
                  required
                  placeholder="you@example.com"
                  error={emailError || undefined}
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Satisfaction Rating</Heading>
                {(props.satisfactionLabels || []).length === 0 ? (
                  <Alert variant="warning" title="No rating labels provided">
                    Satisfaction options are unavailable.
                  </Alert>
                ) : (
                  <RadioGroup
                    label="How satisfied are you?"
                    value={satisfaction}
                    onChange={setSatisfaction}
                    options={satisfactionOptions}
                    error={!step2Valid ? 'Please select a rating before continuing.' : undefined}
                  />
                )}
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Feature Interests</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant)">
                  Select all features you are interested in.
                </Text>
                {(props.featureOptions || []).length === 0 ? (
                  <Alert variant="info" title="No features available">
