                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text weight="medium">Email</Text><Text>{email || '-'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text weight="medium">Satisfaction</Text><Text>{satisfaction ? `${satisfaction} - ${(props.satisfactionLabels || [])[Number(satisfaction) - 1] || ''}` : '-'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text weight="medium">Features</Text>
                      {features.length === 0 ? <Text>-</Text> : <Text>{features.join(', ')}</Text>}
                    </Stack>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text weight="medium">Comments</Text>
                      <Text>{comments.trim() || '-'}</Text>
                    </Stack>
                  </Stack>
                </Card>
                {submitted && (
                  <Alert variant="success" title="Submitted">
                    Your survey responses have been submitted.
                  </Alert>
                )}
              </Stack>
            )}

            <Divider margin="var(--ggui-spacing-2)" />
            <Row justify="between" align="center">
              <Button variant="outline" disabled={step === 1} onClick={handleBack}>
                Back
              </Button>
              {step < totalSteps ? (
                <Button variant="primary" disabled={!canNext} onClick={handleNext}>
                  Next
                </Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit}>
                  Submit
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

