// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Place helper components here if needed
const priorityBadgeVariant = (priority?: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' | 'default' => {
  if (priority === 'high') return 'error';
  if (priority === 'medium') return 'warning';
  if (priority === 'low') return 'success';
  return 'default';
};

const normalizeColumnId = (columnId?: string): string => columnId || 'todo';

const createTaskId = (): string => `task-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [tasksState, setTasksState] = useState<Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>>(props.tasks || []);
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');
  const [addFormColumn, setAddFormColumn] = useState<string>('');
  const [newTaskTitle, setNewTaskTitle] = useState<string>('');
  const [newTaskPriority, setNewTaskPriority] = useState<string>('medium');

  useEffect(() => {
    setTasksState(props.tasks || []);
  }, [props.tasks]);

  useEffect(() => {
    const evt = taskChanged.latest;
    if (!evt || !evt.task || !evt.task.id) return;

    if (evt.action === 'delete') {
      setTasksState((prev) => prev.filter((t) => t.id !== evt.task?.id));
      return;
    }

    if (evt.action === 'create') {
      setTasksState((prev) => {
        const exists = prev.some((t) => t.id === evt.task?.id);
        if (exists) {
          return prev.map((t) => (t.id === evt.task?.id ? { ...t, ...evt.task } : t));
        }
        return [...prev, evt.task];
      });
      return;
    }

    setTasksState((prev) => prev.map((t) => (t.id === evt.task?.id ? { ...t, ...evt.task } : t)));
  }, [taskChanged.latest]);

  const columnOptions = useMemo(() => {
    return (props.columns || []).map((column) => ({
      value: column.id || '',
      label: column.name || 'Unnamed',
    }));
  }, [props.columns]);

  const completedColumnId = useMemo(() => {
    const doneColumn = (props.columns || []).find((c) => (c.name || '').toLowerCase() === 'done');
    return doneColumn?.id || 'done';
  }, [props.columns]);

  const totalTasks = tasksState.length;
  const completedCount = tasksState.filter((task) => normalizeColumnId(task.column) === completedColumnId).length;

  const moveTask = useCallback(
    (taskId: string, toColumn: string) => {
      setTasksState((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: toColumn } : task)));
      taskUpdate({ action: 'move', taskId, data: { column: toColumn } });
    },
    [taskUpdate]
  );

  const startEditTask = useCallback((taskId: string, currentTitle?: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle || '');
  }, []);

  const saveEditTask = useCallback(
    (taskId: string) => {
      const titleToSave = editingTitle.trim();
      if (!titleToSave) return;
      setTasksState((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: titleToSave } : task)));
      taskUpdate({ action: 'edit', taskId, data: { title: titleToSave } as unknown as { column: string } });
      setEditingTaskId('');
      setEditingTitle('');
    },
    [editingTitle, taskUpdate]
  );

  const addTaskToColumn = useCallback(
    () => {
      const title = newTaskTitle.trim();
      if (!title) return;
      const newId = createTaskId();
      const newTask = {
        id: newId,
        title,
        priority: (newTaskPriority as 'low' | 'medium' | 'high') || 'medium',
        assignee: '',
        column: 'todo',
        dueDate: '',
      };
      setTasksState((prev) => [...prev, newTask]);
      taskUpdate({ action: 'create', taskId: newId, data: newTask as unknown as { column: string } });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddFormColumn('');
    },
    [newTaskPriority, newTaskTitle, taskUpdate]
  );


  const tasksByColumn = useMemo(() => {
    const map: Record<string, Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>> = {};
    (props.columns || []).forEach((column) => {
      const key = column.id || '';
      map[key] = tasksState.filter((task) => normalizeColumnId(task.column) === key);
    });
    return map;
  }, [props.columns, tasksState]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Row justify="between" align="center" wrap>
            <Heading level={3}>Team Task Board</Heading>
            <Row gap="var(--ggui-spacing-3)">
              <Badge variant="primary">Total: {totalTasks}</Badge>
              <Badge variant="success">Completed: {completedCount}</Badge>
            </Row>
          </Row>
        </Card>

        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {(props.columns || []).map((column) => {
            const colId = column.id || '';
            const colTasks = tasksByColumn[colId] || [];
            return (
              <Card
                key={colId || column.name}
                padding="var(--ggui-spacing-4)"
                border
                shadow="sm"
              >
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between" align="center">
                    <Heading level={4}>{column.name || 'Unnamed Column'}</Heading>
                    <Badge variant="default">{colTasks.length}</Badge>
                  </Row>

                  <Stack gap="var(--ggui-spacing-3)">
                    {colTasks.length === 0 ? (
                      <Text color="var(--ggui-color-onSurfaceVariant)">No tasks yet</Text>
                    ) : (
                      colTasks.map((task) => {
                        const taskId = task.id || '';
                        const assigneeText = (task.assignee || '').trim();
                        return (
                          <Card key={taskId} padding="var(--ggui-spacing-3)" border shadow="none">
                            <Stack gap="var(--ggui-spacing-2)">
                              <Row justify="between" align="center" wrap>
                                {editingTaskId === taskId ? (
                                  <Input
                                    label="Edit task title"
                                    value={editingTitle}
                                    onChange={setEditingTitle}
                                    placeholder="Task title"
                                  />
                                ) : (
                                  <Text
                                    as={Clickable}
                                    onDoubleClick={() => startEditTask(taskId, task.title)}
                                    color="var(--ggui-color-onSurface)"
                                  >
                                    {task.title || 'Untitled task'}
                                  </Text>
                                )}
                                <Badge variant={priorityBadgeVariant(task.priority)}>{task.priority || 'low'}</Badge>
                              </Row>

                              <Row justify="between" align="center" wrap>
                                <Row gap="var(--ggui-spacing-2)" align="center">
                                  <Avatar name={assigneeText || 'Unassigned'} size="sm" />
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                    {assigneeText || 'Unassigned'}
                                  </Text>
                                </Row>
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  {task.dueDate ? `Due: ${task.dueDate}` : 'No due date'}
                                </Text>
                              </Row>

                              <Select
                                label="Move task"
                                value={normalizeColumnId(task.column)}
                                onChange={(value) => moveTask(taskId, value)}
                                options={columnOptions}
                              />

                              <Row gap="var(--ggui-spacing-2)" justify="end">
                                {editingTaskId === taskId ? (
                                  <Button variant="primary" size="sm" onClick={() => saveEditTask(taskId)}>
                                    Save
                                  </Button>
                                ) : (
                                  <Text
                                    as={Clickable}
                                    onClick={() => startEditTask(taskId, task.title)}
                                    variant="caption"
                                    color="var(--ggui-color-primary-600)"
                                  >
                                    Edit
                                  </Text>
                                )}
                              </Row>
                            </Stack>
                          </Card>
                        );
                      })
                    )}
                  </Stack>

                  {colId === 'todo' ? (
                    addFormColumn === colId ? (
                      <Card padding="var(--ggui-spacing-3)" border shadow="none">
                        <Stack gap="var(--ggui-spacing-2)">
                          <Input
                            label="Task title"
                            value={newTaskTitle}
                            onChange={setNewTaskTitle}
                            placeholder="Enter task title"
                          />
                          <Select
                            label="Priority"
                            value={newTaskPriority}
                            onChange={setNewTaskPriority}
                            options={[
                              { value: 'low', label: 'Low' },
                              { value: 'medium', label: 'Medium' },
                              { value: 'high', label: 'High' },
                            ]}
                          />
                          <Row gap="var(--ggui-spacing-2)">
                            <Button variant="primary" size="sm" onClick={() => addTaskToColumn()}>
                              Create Task
                            </Button>
                            <Button variant="ghost" size="sm" onClick={() => setAddFormColumn('')}>
                              Cancel
                            </Button>
                          </Row>
                        </Stack>
                      </Card>
                    ) : (
                      <Box as={Clickable} onClick={() => setAddFormColumn(colId)}>
                        <Button variant="outline" fullWidth>Add Task</Button>
                      </Box>
                    )
                  ) : null}
                </Stack>
              </Card>
            );
          })}
        </Row>
      </Stack>
    </Container>

  );
}

