}





// Place helper components here if needed
const getCategoryColor = (category?: string): string => {
  const raw = (category || 'unknown').toLowerCase().trim();
  const key = raw.replace(/[-_]+/g, ' ');
  const map: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-error-100)',
    'alkaline earth metal': 'var(--ggui-color-warning-100)',
    'transition metal': 'var(--ggui-color-primary-100)',
    'post-transition metal': 'var(--ggui-color-info-100)',
    metalloid: 'var(--ggui-color-success-100)',
    nonmetal: 'var(--ggui-color-surfaceVariant)',
    halogen: 'var(--ggui-color-warning-50)',
    'noble gas': 'var(--ggui-color-primary-50)',
    lanthanide: 'var(--ggui-color-success-50)',
    actinide: 'var(--ggui-color-error-50)',
    unknown: 'var(--ggui-color-surfaceVariant)',
  };
  return map[key] || map[raw] || 'var(--ggui-color-surfaceVariant)';
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [searchQuery, setSearchQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const normalizedElements = useMemo(() => {
    return (props.elements || []).map((element, index) => ({
      atomicNumber: element.atomicNumber ?? index + 1,
      symbol: element.symbol || '',
      name: element.name || 'Unknown',
      atomicWeight: element.atomicWeight ?? 0,
      category: element.category || 'unknown',
      row: element.row ?? 1,
      col: element.col ?? 1,
    }));
  }, [props.elements]);

  const filteredElements = useMemo(() => {
    const query = searchQuery.trim().toLowerCase();
    if (!query) {
      return normalizedElements;
    }
    return normalizedElements.filter((element) => {
      return element.name.toLowerCase().includes(query) || element.symbol.toLowerCase().includes(query);
    });
  }, [normalizedElements, searchQuery]);

  const categories = useMemo(() => {
    const unique = Array.from(new Set(normalizedElements.map((element) => element.category || 'unknown')));
    return unique.sort((a, b) => a.localeCompare(b));
  }, [normalizedElements]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) {
      return null;
    }
    return normalizedElements.find((element) => element.atomicNumber === selectedAtomicNumber) || null;
  }, [normalizedElements, selectedAtomicNumber]);

  useEffect(() => {
    if (selectedAtomicNumber === null) {
      return;
    }
    const exists = normalizedElements.some((element) => element.atomicNumber === selectedAtomicNumber);
    if (!exists) {
      setSelectedAtomicNumber(null);
    }
  }, [normalizedElements, selectedAtomicNumber]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={2}>Interactive Periodic Table</Heading>

        <Input
          label="Search elements by name or symbol"
          placeholder="Type e.g. Hydrogen or H"
          value={searchQuery}
          onChange={setSearchQuery}
          type="search"
        />

        {normalizedElements.length === 0 ? (
          <Alert variant="info" title="No element data">
            No periodic table data is available.
          </Alert>
        ) : (
          <Card padding="var(--ggui-spacing-4)" border shadow="sm">
            <Box
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(18, minmax(44px, 1fr))',
                gap: 'var(--ggui-spacing-2)',
                overflowX: 'auto',
                padding: 'var(--ggui-spacing-2)',
              }}
            >
              {filteredElements.map((element) => {
                const isSelected = selectedElement?.atomicNumber === element.atomicNumber;
                return (
                  <Card
                    key={element.atomicNumber}
                    as={Clickable}
                    onClick={() => setSelectedAtomicNumber(element.atomicNumber)}
                    padding="var(--ggui-spacing-2)"
                    shadow="none"
                    border
                    radius="md"
                    style={{
                      gridColumn: String(element.col),
                      gridRow: String(element.row),
                      background: getCategoryColor(element.category),
                      minHeight: '72px',
                      position: 'relative',
                      outline: isSelected ? '2px solid var(--ggui-color-primary-600)' : 'none',
                      outlineOffset: '1px',
                    }}
                    hoverStyle={{ opacity: 0.92 }}
                    focusStyle={{ outline: '2px solid var(--ggui-color-primary-600)', outlineOffset: '2px' }}
                  >
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant)"
                      is="span"
                      style={{ position: 'absolute', top: 'var(--ggui-spacing-1)', left: 'var(--ggui-spacing-1)' }}
                    >
                      {element.atomicNumber}
                    </Text>
                    <Stack align="center" justify="center" style={{ height: '100%' }}>
                      <Text size="xl" weight="bold" align="center" is="span">
                        {element.symbol}
                      </Text>
                    </Stack>
                  </Card>
                );
              })}
            </Box>
            {filteredElements.length === 0 && (
              <Box padding="var(--ggui-spacing-4)">
                <Text color="var(--ggui-color-onSurfaceVariant)">No elements match your search.</Text>
              </Box>
            )}
          </Card>
        )}

        <Card padding="var(--ggui-spacing-4)" border shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4}>Element Details</Heading>
            {selectedElement ? (
              <Stack gap="var(--ggui-spacing-2)">
                <Text><Text weight="semibold" is="span">Name:</Text> {selectedElement.name}</Text>
                <Text><Text weight="semibold" is="span">Symbol:</Text> {selectedElement.symbol}</Text>
                <Text><Text weight="semibold" is="span">Atomic Number:</Text> {selectedElement.atomicNumber}</Text>
                <Text><Text weight="semibold" is="span">Atomic Weight:</Text> {selectedElement.atomicWeight}</Text>
                <Text><Text weight="semibold" is="span">Category:</Text> {selectedElement.category}</Text>
              </Stack>
            ) : (
              <Text color="var(--ggui-color-onSurfaceVariant)">Select an element to view details.</Text>
            )}
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4)" border shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4}>Legend</Heading>
            <Row wrap gap="var(--ggui-spacing-3)">
              {categories.map((category) => (
                <Row key={category} align="center" gap="var(--ggui-spacing-2)">
                  <Box
                    style={{
                      width: '16px',
