import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// Place helper components here if needed
type ChatMessageItem = { sender: string; text: string; timestamp: string };

function toSafeMessage(input: { sender?: string; text?: string; timestamp?: string }): ChatMessageItem {
  return {
    sender: input.sender && input.sender.trim() ? input.sender : 'Unknown',
    text: input.text ?? '',
    timestamp: input.timestamp ?? new Date().toISOString(),
  };
}

function formatMessageTime(timestamp: string): string {
  const parsed = new Date(timestamp);
  if (Number.isNaN(parsed.getTime())) {
    return timestamp;
  }
  return parsed.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [allMessages, setAllMessages] = useState<ChatMessageItem[]>(() =>
    (props.messages ?? []).map((item) => toSafeMessage(item)),
  );
  const [draftMessage, setDraftMessage] = useState<string>('');
  const [typingState, setTypingState] = useState<{ sender: string; active: boolean }>({ sender: '', active: false });
  const messageListRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setAllMessages((props.messages ?? []).map((item) => toSafeMessage(item)));
  }, [props.messages]);

  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, toSafeMessage(message.latest)]);
    }
  }, [message.latest]);

  useEffect(() => {
    if (typing.latest) {
      setTypingState({
        sender: typing.latest.sender && typing.latest.sender.trim() ? typing.latest.sender : '',
        active: Boolean(typing.latest.active),
      });
    }
  }, [typing.latest]);

  useEffect(() => {
    if (messageListRef.current) {
      messageListRef.current.scrollTop = messageListRef.current.scrollHeight;
    }
  }, [allMessages, typingState.active]);

  const groupedMessages = useMemo(() => {
    return allMessages.reduce<Array<{ sender: string; isCurrentUser: boolean; items: ChatMessageItem[] }>>((acc, current) => {
      const isCurrentUser = current.sender === props.currentUser;
      const lastGroup = acc[acc.length - 1];
      if (lastGroup && lastGroup.sender === current.sender) {
        return [
          ...acc.slice(0, -1),
          {
            ...lastGroup,
            items: [...lastGroup.items, current],
          },
        ];
      }
      return [...acc, { sender: current.sender, isCurrentUser, items: [current] }];
    }, []);
  }, [allMessages, props.currentUser]);

  const handleSendMessage = useCallback(() => {
    const trimmed = draftMessage.trim();
    if (!trimmed) {
      return;
    }
    const timestamp = new Date().toISOString();
    sendMessage({ text: trimmed, timestamp });
    setAllMessages((prev) => [...prev, { sender: props.currentUser, text: trimmed, timestamp }]);
    setDraftMessage('');
  }, [draftMessage, props.currentUser, sendMessage]);

  const showTypingIndicator = typingState.active && typingState.sender && typingState.sender !== props.currentUser;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-4)"
        radius="lg"
        shadow="sm"
        border
      >
        <Stack gap="var(--ggui-spacing-4)">
          <Row justify="between" align="center">
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Heading level={3} color="var(--ggui-color-onSurface)">{props.title}</Heading>
              <Badge variant="primary" size="sm">{props.participantCount} participants</Badge>
            </Row>
            {showTypingIndicator ? (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {typingState.sender} is typing...
              </Text>
            ) : (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                &nbsp;
              </Text>
            )}
          </Row>

          <Box
            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-lg)"
          >
            <Stack
              gap="var(--ggui-spacing-3)"
            >
              <Box>
                <div
                  ref={messageListRef}
                  style={{
                    maxHeight: '60vh',
                    overflowY: 'auto',
                    paddingRight: 'var(--ggui-spacing-1)',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-3)">
                    {groupedMessages.length === 0 ? (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        No messages yet.
                      </Text>
                    ) : (
                      groupedMessages.map((group, groupIndex) => (
                        <Stack
                          key={`${group.sender}-${groupIndex}`}
                          gap="var(--ggui-spacing-1)"
                          align={group.isCurrentUser ? 'end' : 'start'}
                        >
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                            {group.sender}
                          </Text>
                          <Stack gap="var(--ggui-spacing-1)" align={group.isCurrentUser ? 'end' : 'start'}>
                            {group.items.map((msg, msgIndex) => (
                              <Box
                                key={`${group.sender}-${groupIndex}-${msgIndex}`}
                                padding="var(--ggui-spacing-2)"
                                background={group.isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                                borderRadius="var(--ggui-shape-radius-md)"
                              >
                                <Stack gap="var(--ggui-spacing-1)">
                                  <Text
                                    variant="bodySmall"
                                    color={group.isCurrentUser ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}
                                  >
                                    {msg.text}
                                  </Text>
                                  <Text
                                    variant="caption"
                                    color={group.isCurrentUser ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-onSurfaceVariant)'}
                                    align={group.isCurrentUser ? 'right' : 'left'}
                                  >
                                    {formatMessageTime(msg.timestamp)}
                                  </Text>
                                </Stack>
                              </Box>
                            ))}
                          </Stack>
                        </Stack>
                      ))
                    )}
                  </Stack>
                </div>
              </Box>

              <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

              <Row gap="var(--ggui-spacing-2)" align="end">
                <Box
                  style={{ flex: 1 } as React.CSSProperties}
                >
                  <Input
                    label="Message"
                    placeholder="Type a message..."
                    value={draftMessage}
                    onChange={setDraftMessage}
                    onKeyDown={(event) => {
                      if (event.key === 'Enter') {
                        event.preventDefault();
                        handleSendMessage();
                      }
                    }}
                  />
                </Box>
                <Button
                  as={Clickable}
                  onClick={handleSendMessage}
                  variant="primary"
                  disabled={!draftMessage.trim()}
                >
                  Send
                </Button>
              </Row>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>

  );
}

